import sys

class Solution:
    def solve(self, matrix: list[list[int]]) -> float:
        # flatten and sort
        flat = []
        for row in matrix:
            flat.extend(row)
        flat.sort()
        n = len(flat)
        if n % 2 == 1:
            return float(flat[n // 2])
        else:
            return (flat[n // 2 - 1] + flat[n // 2]) / 2.0

