#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    double solve(vector<vector<int>>& matrix) {
        vector<int> flat;
        for (auto &row : matrix) {
            flat.insert(flat.end(), row.begin(), row.end());
        }
        sort(flat.begin(), flat.end());
        size_t n = flat.size();
        if (n % 2 == 1) {
            return static_cast<double>(flat[n/2]);
        } else {
            return (flat[n/2 - 1] + flat[n/2]) / 2.0;
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N, M;
    if (!(cin >> N >> M)) return 0; // M is unused due to variable row lengths
    vector<vector<int>> matrix;
    for (int i = 0; i < N; ++i) {
        int cnt;
        if (!(cin >> cnt)) break;
        vector<int> row(cnt);
        for (int j = 0; j < cnt; ++j) {
            cin >> row[j];
        }
        matrix.push_back(move(row));
    }
    Solution sol;
    double median = sol.solve(matrix);
    // Output without unnecessary decimal part
    if (fabs(median - round(median)) < 1e-9) {
        cout << static_cast<long long>(llround(median));
    } else {
        // Print with up to 10 decimal places, trimming trailing zeros
        ostringstream oss;
        oss << fixed << setprecision(10) << median;
        string s = oss.str();
        // trim trailing zeros and possible dot
        while (!s.empty() && s.back() == '0') s.pop_back();
        if (!s.empty() && s.back() == '.') s.pop_back();
        cout << s;
    }
    return 0;
}
